const input = $json;

const telefone = String(
  $('Buscar Empresas').item.json.whatsapp ||
  $json.telefone ||
  ''
).replace(/\D/g, '');

const payload = input.payload || [];

const contato = payload.find(contact => {
  const identifier = String(contact.identifier || '').trim();
  const identifierLimpo = identifier.replace(/\D/g, '');
  const phoneNumber = String(contact.phone_number || '').replace(/\D/g, '');
  const name = String(contact.name || '');

  const ehGrupo =
    identifier.includes('@g.us') ||
    name.includes('(GROUP)');

  const ehContatoIndividual =
    identifier === `${telefone}@s.whatsapp.net` ||
    identifier === telefone ||
    identifierLimpo === telefone ||
    phoneNumber === telefone;

  return !ehGrupo && ehContatoIndividual;
});

const contactInbox20 = contato?.contact_inboxes?.find(ci =>
  Number(ci.inbox?.id) === 20
);

return [
  {
    json: {
      found: !!contato,
      contact_id: contato?.id || null,
      name: contato?.name || null,
      phone_number: contato?.phone_number || null,
      identifier: contato?.identifier || null,
      source_id: contactInbox20?.source_id || null,
      inbox_id: contactInbox20?.inbox?.id || null,
      channel_type: contactInbox20?.inbox?.channel_type || null,
      provider: contactInbox20?.inbox?.provider || null,
      contact: contato || null
    }
  }
];

