const input = $json;

const conversations = input.payload || [];

const inboxIdDesejado = 20;

const conversasInbox20 = conversations.filter(conv => {
  return Number(conv.inbox_id) === inboxIdDesejado;
});

const conversaAbertaInbox20 = conversasInbox20.find(conv => {
  return conv.status === 'open';
});

const conversaSelecionada =
  conversaAbertaInbox20 ||
  conversasInbox20.sort((a, b) => {
    return Number(b.last_activity_at || b.updated_at || b.created_at || 0) -
           Number(a.last_activity_at || a.updated_at || a.created_at || 0);
  })[0] ||
  null;

return [
  {
    json: {
      tem_conversa_inbox_20: !!conversaSelecionada,
      conversation_id: conversaSelecionada?.id || null,
      conversation_status: conversaSelecionada?.status || null,
      can_reply: conversaSelecionada?.can_reply ?? false,
      inbox_id: conversaSelecionada?.inbox_id || null,
      source_id: conversaSelecionada?.messages?.[0]?.conversation?.contact_inbox?.source_id
        || conversaSelecionada?.last_non_activity_message?.conversation?.contact_inbox?.source_id
        || null,
      precisa_criar_conversa: !conversaSelecionada,
      conversa: conversaSelecionada
    }
  }
];

